1371   if (OldLatch) {
1372     BasicBlock *NewLatch = L->getLoopLatch();
1373     if (NewLatch != OldLatch) {
1374       MDNode *MD = OldLatch->getTerminator()->getMetadata(LLVMContext::MD_loop);
