7979   if (Unreachable)
7980     Unreachable->removePredecessor(BB);
7981   SI->eraseFromParent();
7982   Cmp->eraseFromParent();
7983   if (DTU && Unreachable)
7984     DTU->applyUpdates({{DominatorTree::Delete, BB, Unreachable}});
7985   return true;
7986 }
